package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValueOf() {
        // Given
        String format = "DEFAULT";

        // Mock Predefined class
        CSVFormat.Predefined predefined = mock(CSVFormat.Predefined.class);
        when(predefined.getFormat()).thenReturn(CSVFormat.DEFAULT);

        try {
            // Mock valueOf method in Predefined enum
            when(CSVFormat.Predefined.valueOf(format)).thenReturn(predefined);
        } catch (IllegalArgumentException e) {
            // Handle exception for invalid format
        }

        // When
        CSVFormat result = CSVFormat.valueOf(format);

        // Then
        assertEquals(CSVFormat.DEFAULT, result);
    }
}
